import{_ as l,o as i,c as e,ak as r}from"./chunks/framework.DMc2NN9G.js";const c=JSON.parse('{"title":"数据链路层设备 —— 集线器（Hub）","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/集线器连接多台主机.md","filePath":"计算机网络/物理层和数据链路层/集线器连接多台主机.md","lastUpdated":1775305895000}'),n={name:"计算机网络/物理层和数据链路层/集线器连接多台主机.md"};function s(t,a,h,d,o,b){return i(),e("div",null,[...a[0]||(a[0]=[r(`<h1 id="数据链路层设备-——-集线器-hub" tabindex="-1">数据链路层设备 —— 集线器（Hub） <a class="header-anchor" href="#数据链路层设备-——-集线器-hub" aria-label="Permalink to “数据链路层设备 —— 集线器（Hub）”">​</a></h1><h2 id="一、问题背景-多主机如何互联" tabindex="-1">一、问题背景：多主机如何互联？ <a class="header-anchor" href="#一、问题背景-多主机如何互联" aria-label="Permalink to “一、问题背景：多主机如何互联？”">​</a></h2><h3 id="_1️⃣-两台主机" tabindex="-1">1️⃣ 两台主机 <a class="header-anchor" href="#_1️⃣-两台主机" aria-label="Permalink to “1️⃣ 两台主机”">​</a></h3><ul><li>直接连接即可（点对点通信）</li><li>可以实现基本通信（如打游戏）</li></ul><hr><h3 id="_2️⃣-多台主机问题" tabindex="-1">2️⃣ 多台主机问题 <a class="header-anchor" href="#_2️⃣-多台主机问题" aria-label="Permalink to “2️⃣ 多台主机问题”">​</a></h3><p>如果主机数量增加：</p><p>❌ 两两连接的问题：</p><ul><li>连接复杂度高（O(n²)）</li><li>布线极其混乱</li><li>不可扩展</li></ul><hr><h2 id="二、早期方案-总线型网络" tabindex="-1">二、早期方案：总线型网络 <a class="header-anchor" href="#二、早期方案-总线型网络" aria-label="Permalink to “二、早期方案：总线型网络”">​</a></h2><h3 id="结构特点" tabindex="-1">结构特点 <a class="header-anchor" href="#结构特点" aria-label="Permalink to “结构特点”">​</a></h3><ul><li>所有主机连接到一条“总线”上</li><li>数据在总线上广播</li></ul><hr><h3 id="❗-存在问题" tabindex="-1">❗ 存在问题 <a class="header-anchor" href="#❗-存在问题" aria-label="Permalink to “❗ 存在问题”">​</a></h3><ol><li><strong>冲突（Collision）问题</strong><ul><li>多台主机同时发送 → 信号碰撞</li></ul></li><li><strong>单点故障</strong><ul><li>总线断裂 → 整个网络瘫痪</li></ul></li><li><strong>维护困难</strong><ul><li>更换总线成本高</li></ul></li></ol><hr><h3 id="✅-解决冲突的方法" tabindex="-1">✅ 解决冲突的方法 <a class="header-anchor" href="#✅-解决冲突的方法" aria-label="Permalink to “✅ 解决冲突的方法”">​</a></h3><p>👉 使用 <strong>CSMA/CD 协议</strong></p><p>（Carrier Sense Multiple Access with Collision Detection）</p><p>作用：</p><ul><li>监听信道是否空闲</li><li>发送中检测冲突</li><li>冲突后重传</li></ul><hr><h2 id="三、改进方案-集线器-hub" tabindex="-1">三、改进方案：集线器（Hub） <a class="header-anchor" href="#三、改进方案-集线器-hub" aria-label="Permalink to “三、改进方案：集线器（Hub）”">​</a></h2><h3 id="_1️⃣-基本概念" tabindex="-1">1️⃣ 基本概念 <a class="header-anchor" href="#_1️⃣-基本概念" aria-label="Permalink to “1️⃣ 基本概念”">​</a></h3><ul><li>中文：集线器</li><li>英文：Hub</li><li>作用：连接多台主机</li></ul><hr><h3 id="_2️⃣-网络结构" tabindex="-1">2️⃣ 网络结构 <a class="header-anchor" href="#_2️⃣-网络结构" aria-label="Permalink to “2️⃣ 网络结构”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>        A</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>B —— Hub —— C</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        |</span></span>
<span class="line"><span>        D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>👉 星型拓扑（逻辑上仍类似总线）</p><hr><h2 id="四、集线器的工作原理" tabindex="-1">四、集线器的工作原理 <a class="header-anchor" href="#四、集线器的工作原理" aria-label="Permalink to “四、集线器的工作原理”">​</a></h2><h3 id="_1️⃣-所属层次" tabindex="-1">1️⃣ 所属层次 <a class="header-anchor" href="#_1️⃣-所属层次" aria-label="Permalink to “1️⃣ 所属层次”">​</a></h3><p>👉 <strong>物理层设备</strong></p><ul><li>只处理“比特流”</li><li>不解析数据帧</li><li>不识别 MAC 地址</li></ul><hr><h3 id="_2️⃣-核心特点" tabindex="-1">2️⃣ 核心特点 <a class="header-anchor" href="#_2️⃣-核心特点" aria-label="Permalink to “2️⃣ 核心特点”">​</a></h3><h4 id="✅-无智能转发" tabindex="-1">✅ 无智能转发 <a class="header-anchor" href="#✅-无智能转发" aria-label="Permalink to “✅ 无智能转发”">​</a></h4><ul><li>不知道目标是谁</li><li>不学习地址</li><li>不做决策</li></ul><hr><h4 id="✅-广播转发机制" tabindex="-1">✅ 广播转发机制 <a class="header-anchor" href="#✅-广播转发机制" aria-label="Permalink to “✅ 广播转发机制”">​</a></h4><p>👉 行为规则：</p><blockquote><p>从一个端口收到数据 → 向其他所有端口转发</p></blockquote><hr><h3 id="_3️⃣-转发流程示例" tabindex="-1">3️⃣ 转发流程示例 <a class="header-anchor" href="#_3️⃣-转发流程示例" aria-label="Permalink to “3️⃣ 转发流程示例”">​</a></h3><h4 id="场景-a-→-d" tabindex="-1">场景：A → D <a class="header-anchor" href="#场景-a-→-d" aria-label="Permalink to “场景：A → D”">​</a></h4><ol><li>A 发送数据（包含目标 MAC：D）</li><li>数据进入 Hub</li><li>Hub 执行：</li></ol><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>输入端口：1</span></span>
<span class="line"><span>输出端口：2、3、4（全部转发）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><ol><li>各主机处理：</li></ol><table tabindex="0"><thead><tr><th>主机</th><th>行为</th></tr></thead><tbody><tr><td>B</td><td>MAC 不匹配 → 丢弃</td></tr><tr><td>C</td><td>MAC 不匹配 → 丢弃</td></tr><tr><td>D</td><td>MAC 匹配 → 接收</td></tr></tbody></table><hr><h3 id="_4️⃣-回包过程-d-→-a" tabindex="-1">4️⃣ 回包过程（D → A） <a class="header-anchor" href="#_4️⃣-回包过程-d-→-a" aria-label="Permalink to “4️⃣ 回包过程（D → A）”">​</a></h3><ol><li>D 读取 A 的 MAC 地址（来自之前数据）</li><li>构造数据帧： <ul><li>源 MAC：D</li><li>目的 MAC：A</li></ul></li><li>发送到 Hub</li><li>Hub 再次广播</li><li>A 接收，其它主机丢弃</li></ol><hr><h2 id="五、关键问题-冲突仍然存在" tabindex="-1">五、关键问题：冲突仍然存在 <a class="header-anchor" href="#五、关键问题-冲突仍然存在" aria-label="Permalink to “五、关键问题：冲突仍然存在”">​</a></h2><h3 id="❗-为什么" tabindex="-1">❗ 为什么？ <a class="header-anchor" href="#❗-为什么" aria-label="Permalink to “❗ 为什么？”">​</a></h3><p>因为 Hub 的广播机制：</p><ul><li>所有设备共享同一信道</li><li>同时发送 → 冲突不可避免</li></ul><hr><h3 id="✅-结论" tabindex="-1">✅ 结论 <a class="header-anchor" href="#✅-结论" aria-label="Permalink to “✅ 结论”">​</a></h3><p>👉 使用 Hub 的网络：</p><ul><li>仍然是 <strong>共享介质网络</strong></li><li>必须使用 <strong>CSMA/CD 协议</strong></li></ul><hr><h2 id="六、集线器的优缺点" tabindex="-1">六、集线器的优缺点 <a class="header-anchor" href="#六、集线器的优缺点" aria-label="Permalink to “六、集线器的优缺点”">​</a></h2><h3 id="✅-优点" tabindex="-1">✅ 优点 <a class="header-anchor" href="#✅-优点" aria-label="Permalink to “✅ 优点”">​</a></h3><ul><li>结构简单</li><li>成本低</li><li>易于扩展（比总线好）</li></ul><hr><h3 id="❌-缺点-重点" tabindex="-1">❌ 缺点（重点） <a class="header-anchor" href="#❌-缺点-重点" aria-label="Permalink to “❌ 缺点（重点）”">​</a></h3><ol><li><strong>无智能</strong></li><li><strong>广播风暴</strong></li><li><strong>冲突严重</strong></li><li><strong>带宽共享</strong></li><li><strong>安全性差（所有主机都能收到数据）</strong></li></ol><hr><h2 id="七、核心总结-面试重点" tabindex="-1">七、核心总结（面试重点） <a class="header-anchor" href="#七、核心总结-面试重点" aria-label="Permalink to “七、核心总结（面试重点）”">​</a></h2><h3 id="⭐-一句话总结" tabindex="-1">⭐ 一句话总结 <a class="header-anchor" href="#⭐-一句话总结" aria-label="Permalink to “⭐ 一句话总结”">​</a></h3><blockquote><p>集线器 = 物理层设备 + 广播转发 + 无智能</p></blockquote><hr><h3 id="⭐-对比关键点" tabindex="-1">⭐ 对比关键点 <a class="header-anchor" href="#⭐-对比关键点" aria-label="Permalink to “⭐ 对比关键点”">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>集线器</th></tr></thead><tbody><tr><td>工作层</td><td>物理层</td></tr><tr><td>是否识别 MAC</td><td>❌</td></tr><tr><td>转发方式</td><td>广播</td></tr><tr><td>是否有冲突</td><td>✅</td></tr><tr><td>是否智能</td><td>❌</td></tr></tbody></table><hr><h2 id="八、引出下一步" tabindex="-1">八、引出下一步 <a class="header-anchor" href="#八、引出下一步" aria-label="Permalink to “八、引出下一步”">​</a></h2><p>👉 集线器的问题：</p><ul><li>冲突严重</li><li>效率低</li></ul><p>👉 解决方案：</p><p>➡️ <strong>交换机（Switch）</strong></p><p>（下一节核心内容）</p><hr><p>如果你愿意，我可以帮你把<strong>“集线器 vs 交换机 vs 路由器”做一张一眼秒懂的对比图（面试杀手级）</strong>，这块是高频考点。</p>`,86)])])}const u=l(n,[["render",s]]);export{c as __pageData,u as default};
